@startuml Combat Subsystem Class Diagram

class CombatManager {
    "C" CombatManager
}

class Player {
    "C" Player
}

class Combat {
    "C" Combat
    Combatants allies
    Combatants enemies
    Inventory reward
    Move playerMove
    Move npcMove
    turn()
}

class Move {
    "C" Move
    String name
    int blockPercent
    double damage
    double healing
}

class Combatants {
    "C" Combatants
}

class Inventory {
    "C" Inventory
}

class Entity {
    "C" Entity
}

CombatManager ..> Player : 0..*
CombatManager -- Combat : 1

Combat -- Combatants : 2
Combat -- Inventory : 1

Combatants ..> Entity : 0..*
Combatants ..> Move : 2
Inventory ..> Move : 2

@enduml
